  it("sums lines with no discount", () => {
    expect(orderTotalCents([{ unitCents: 500, qty: 2 }], 0)).toBe(1000);
  });

  it("rounds the discounted order subtotal once, not per line", () => {
    // Two lines of 555c at 19% off. Subtotal 1110c * 0.81 = 899.1c -> $8.99.
    // Rounding each line (449.55 -> 450) and summing drifts up to 900c ($9.00).
    const lines = [
      { unitCents: 555, qty: 1 },
      { unitCents: 555, qty: 1 },
    ];
    expect(orderTotalCents(lines, 19)).toBe(899);
  });
});

